const fs = require('fs');
const path = require('path');

function batchWrite(files) {
  files.forEach((file) => {
    const filePath = path.join(__dirname, file.path);
    fs.writeFileSync(filePath, file.content);
  });
}

batchWrite([
  { path: "batch-chat-1.js", content: "console.log(1)" },
  { path: "batch-chat-2.js", content: "console.log(2)" }
]);
